INSERT INTO `articles` (`id`, `title`, `description`, `image`, `content`, `created_at`, `updated_at`) VALUES
(1, 'เซ็นทรัลพัฒนา เรซซิเด้นซ์ รุกแนวราบในกรุงเทพฯ มูลค่ากว่า 2.5 หมื่นล้าน', 'เซ็นทรัลพัฒนา เรซซิเด้นซ์ รุกตลาดแนวราบในกรุงเทพฯ มูลค่ารวมกว่า 2.5 หมื่นล้าน ครบทุกเซ็กเมนต์ ด้วย 4 แบรนด์ \"นิยาม-นิรดา-นินญา-นิรติ\" ตอกย้ำคุณภาพทุกมิติ', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=600', '[PR News] 11 ปี เซ็นทรัลพัฒนา เรซซิเด้นซ์ 51 โครงการ 65,700 ล้านบาท ประกาศรุกตลาดแนวราบในกรุงเทพฯ มูลค่ารวมกว่า 25,340 ล้านบาท ครบทุกเซ็กเมนต์ ด้วย 4 แบรนด์\n\nร.อ.กรี เดชชัย กรรมการผู้จัดการใหญ่ ธุรกิจที่อยู่อาศัย บริษัท เซ็นทรัลพัฒนา จำกัด (มหาชน) เปิดเผยว่า เซ็นทรัลพัฒนา เรซซิเด้นซ์ ดำเนินธุรกิจพัฒนาโครงการที่อยู่อาศัยมากว่า 10 ปี\n\nกลยุทธ์หลัก 3 ด้าน:\n1. Location-Led Strategy การเลือกทำเลศักยภาพให้กลายเป็นพื้นที่อยู่อาศัยคุณภาพ\n2. Brand Portfolio Strategy การสร้างเอกลักษณ์ของแต่ละแบรนด์อย่างชัดเจน\n3. Customer-Centric Experience การสร้างประสบการณ์ก่อนและหลังการขาย', '2026-04-19 09:35:58', '2026-04-19 09:35:58'),
(2, 'เซ็นทรัลพัฒนาฯ เปิดตัว บ้านนินญา รามอินทรา 83 บ้านเดี่ยวระดับพรีเมียม', 'เซ็นทรัลพัฒนา เรซซิเด้นซ์ เปิดตัวโครงการบ้านแนวคิดใหม่ บ้านนินญา รามอินทรา 83 บ้านเดี่ยว 3 ชั้น ระดับพรีเมียมที่ออกแบบมาเพื่อตอบโจทย์วิถีชีวิตของครอบครัวยุคใหม่', 'https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=600', 'บ้านนินญา รามอินทรา 83 เป็นโครงการบ้านเดี่ยว 3 ชั้น ระดับพรีเมียม บนทำเลรามอินทรา\n\nจุดเด่นของโครงการ:\n- บ้านเดี่ยว 3 ชั้น พื้นที่ใช้สอย 320–450 ตร.ม.\n- ระบบความปลอดภัย 7 ระดับ\n- สิทธิพิเศษ Central Citizens เข้าถึงสิทธิประโยชน์จากเครือเซ็นทรัล\n- ทีมบริหารนิติบุคคลมืออาชีพดูแลตลอด 24 ชั่วโมง', '2026-04-19 09:35:58', '2026-04-19 09:35:58'),
(3, 'อนันดาฯ จับมือ ดิ แอสคอทท์ ลิมิเต็ด ชูแบรนด์ \"คัลเจอร์\" ยกระดับคอนโด', 'อนันดาฯ ชูแบรนด์ คัลเจอร์ ผนึกกำลังพันธมิตรระดับโลก ดิ แอสคอทท์ ลิมิเต็ด ยกระดับคอนโดสู่ประสบการณ์การอยู่อาศัยมาตรฐานโรงแรม 5 ดาว', 'https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?w=600', 'อนันดา ดีเวลลอปเม้นท์ จับมือ ดิ แอสคอทท์ ลิมิเต็ด พัฒนาแบรนด์คอนโด \"คัลเจอร์\"\n\nไฮไลต์ความร่วมมือ:\n- บริการ Serviced Residence มาตรฐาน Ascott\n- สิ่งอำนวยความสะดวกครบครัน เช่น ฟิตเนส สระว่ายน้ำ ห้องประชุม\n- ทำเลกลางเมือง ใกล้รถไฟฟ้า BTS/MRT\n- เหมาะสำหรับนักลงทุนและผู้ต้องการ lifestyle ระดับพรีเมียม', '2026-04-19 09:35:58', '2026-04-19 09:35:58'),
(4, 'ลดหย่อนภาษี 2568 เอกสารยื่นภาษี 2568 ที่ต้องใช้ หักลดหย่อนอะไรได้บ้าง', 'ลดหย่อนภาษี 2568 กับกรมสรรพากร เตรียมความพร้อมก่อนยื่นภาษี 2568 ได้ถึงเมื่อไหร่ ยื่นภาษีล่าช้ามีโทษอย่างไร', 'https://images.unsplash.com/photo-1554224155-8d04cb21cd6c?w=600', 'สรุปสิทธิลดหย่อนภาษีเงินได้บุคคลธรรมดา ปีภาษี 2568\n\nรายการลดหย่อนหลัก:\n1. ค่าลดหย่อนส่วนตัว 60,000 บาท\n2. ค่าลดหย่อนคู่สมรส 60,000 บาท\n3. ค่าลดหย่อนบุตร คนละ 30,000 บาท (สูงสุด 3 คน)\n4. ดอกเบี้ยเงินกู้บ้าน สูงสุด 100,000 บาท\n5. เบี้ยประกันชีวิต สูงสุด 100,000 บาท\n6. กองทุน RMF/SSF ตามเงื่อนไขกำหนด\n\nเอกสารที่ต้องใช้:\n- ใบแสดงรายได้ (50 ทวิ)\n- สลิปเงินเดือน\n- ใบเสร็จเบี้ยประกัน\n- หนังสือรับรองดอกเบี้ยจากธนาคาร', '2026-04-19 09:35:58', '2026-04-19 09:35:58'),
(5, 'สิงห์ เอสเตท เปิด 4 แกนหลักสร้างธุรกิจที่สมดุล-สร้างคุณค่าที่ยั่งยืน', 'สิงห์ เอสเตท เปิดทิศทางการขับเคลื่อน 4 แกนหลักสร้างธุรกิจที่สมดุล เดินหน้าขับเคลื่อนองค์กรด้วยกลยุทธ์ที่ให้ความสำคัญกับ \"การสร้างคุณค่าให้ชีวิต\"', 'https://images.unsplash.com/photo-1503387762-592deb58ef4e?w=600', 'สิงห์ เอสเตท ประกาศทิศทางธุรกิจ 4 แกนหลัก มุ่งสร้างความสมดุลและคุณค่าระยะยาว\n\n4 แกนหลักของสิงห์ เอสเตท:\n1. Residential ที่อยู่อาศัยคุณภาพสูง ครบทุกระดับราคา\n2. Commercial อสังหาริมทรัพย์เชิงพาณิชย์ที่สร้างรายได้ต่อเนื่อง\n3. Hospitality โรงแรมและรีสอร์ทระดับพรีเมียมทั้งในและต่างประเทศ\n4. Overseas ขยายการลงทุนในต่างประเทศ ยุโรป และเอเชีย\n\nวิสัยทัศน์ปี 2568-2570:\n- รายได้รวมเติบโต 15% ต่อปี\n- พอร์ตโฟลิโอ ESG ที่แข็งแกร่ง\n- เปิดโครงการใหม่ทุกไตรมาส', '2026-04-19 09:35:58', '2026-04-19 09:35:58');

