(1, 'บ้านหนองกึม', '[\"https://plus.unsplash.com/premium_photo-1684338795288-097525d127f0?q=80&w=1742&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D\"]', 20000000.00, '', 'ลาดพร้าว 15 แยก 2-4\r\nเขต จตุจักร แขวงจอมพล กรุงเทพ 10900', 'กรุงเทพ', 'จตุจักร', 'จอมพล', 5, 5, 100.00, 2, 'บ้านเดี่ยว', '2026-04-08 16:36:17', 9, 'บ้าน', 'homeสำหรับขาย บ้าน 2 ชั้น 5 ห้องนอน 5 ห้องน้ำ พื้นที่ใช้สอย 100 ตร.ม. ตั้งอยู่ในจตุจักร จังหวัดกรุงเทพ สิ่งอำนวยความสะดวกครบครัน ราคา 20,000,000 บาท ()', 13.7293, 100.4808, NULL),
